"use client"

import { useContext } from "react"
import { ProfileContext } from "../../context/profile/ProfileContext"
import Spinner from "../layout/Spinner"

const GithubStats = () => {
  const { githubStats, loading } = useContext(ProfileContext)

  if (loading) {
    return <Spinner />
  }

  if (!githubStats) {
    return (
      <div className="bg-white p-4 rounded-lg shadow-md">
        <h3 className="text-xl font-semibold mb-2">GitHub Stats</h3>
        <p>Add your GitHub profile to see stats here.</p>
      </div>
    )
  }

  // Format date
  const formatDate = (dateString) => {
    if (!dateString) return "N/A"
    const options = { year: "numeric", month: "short", day: "numeric" }
    return new Date(dateString).toLocaleDateString(undefined, options)
  }

  // Calculate active days from contribution history
  const calculateActiveDays = () => {
    if (!githubStats.contributionHistory || githubStats.contributionHistory.length === 0) {
      return 0
    }

    return githubStats.contributionHistory.filter((day) => day && day.count > 0).length
  }

  // Calculate streak
  const calculateStreak = () => {
    if (!githubStats.contributionHistory || githubStats.contributionHistory.length === 0) {
      return 0
    }

    let streak = 0
    const sortedHistory = [...githubStats.contributionHistory].reverse()

    for (const day of sortedHistory) {
      if (day && day.count > 0) {
        streak++
      } else {
        break
      }
    }

    return streak
  }

  const activeDays = calculateActiveDays()
  const currentStreak = calculateStreak()

  return (
    <div className="bg-white p-4 rounded-lg shadow-md">
      <h3 className="text-xl font-semibold mb-4">GitHub Stats</h3>

      {/* Profile Overview */}
      <div className="flex items-start mb-6">
        {githubStats.avatarUrl && (
          <img
            src={githubStats.avatarUrl || "/placeholder.svg"}
            alt={`${githubStats.username}'s avatar`}
            className="w-16 h-16 rounded-full mr-4"
          />
        )}
        <div>
          <h4 className="text-lg font-semibold">{githubStats.name || githubStats.username}</h4>
          {githubStats.bio && <p className="text-gray-600 text-sm">{githubStats.bio}</p>}
          <div className="flex items-center mt-1 text-sm text-gray-500">
            {githubStats.location && <span className="mr-3">{githubStats.location}</span>}
            {githubStats.company && <span className="mr-3">{githubStats.company}</span>}
            {githubStats.blog && (
              <a
                href={githubStats.blog.startsWith("http") ? githubStats.blog : `https://${githubStats.blog}`}
                target="_blank"
                rel="noopener noreferrer"
                className="text-blue-600 hover:underline"
              >
                Website
              </a>
            )}
          </div>
        </div>
      </div>

      <div className="grid grid-cols-2 gap-4 mb-4">
        <div className="bg-gray-100 p-3 rounded">
          <p className="text-sm text-gray-600">Followers</p>
          <p className="text-xl font-bold">{githubStats.followers || 0}</p>
        </div>
        <div className="bg-gray-100 p-3 rounded">
          <p className="text-sm text-gray-600">Following</p>
          <p className="text-xl font-bold">{githubStats.following || 0}</p>
        </div>
        <div className="bg-gray-100 p-3 rounded">
          <p className="text-sm text-gray-600">Public Repos</p>
          <p className="text-xl font-bold">{githubStats.publicRepos || 0}</p>
        </div>
        <div className="bg-gray-100 p-3 rounded">
          <p className="text-sm text-gray-600">Total Stars</p>
          <p className="text-xl font-bold">{githubStats.totalStars || 0}</p>
        </div>
      </div>

      {/* Activity Stats */}
      <div className="grid grid-cols-2 gap-4 mb-4">
        <div className="bg-blue-50 p-3 rounded">
          <p className="text-sm text-gray-600">Active Days</p>
          <p className="text-xl font-bold text-blue-600">{activeDays}</p>
        </div>
        <div className="bg-green-50 p-3 rounded">
          <p className="text-sm text-gray-600">Current Streak</p>
          <p className="text-xl font-bold text-green-600">{currentStreak} days</p>
        </div>
      </div>

      {githubStats.contributionsLastYear > 0 && (
        <div className="mb-4">
          <h4 className="font-semibold mb-2">Contributions This Year</h4>
          <p className="text-2xl font-bold text-green-600">{githubStats.contributionsLastYear}</p>

          {githubStats.contributionHistory && githubStats.contributionHistory.length > 0 && (
            <div className="mt-2">
              <div className="flex flex-wrap gap-1 mt-2">
                {githubStats.contributionHistory.slice(-30).map((day, i) => (
                  <div
                    key={i}
                    className="w-3 h-3 rounded-sm"
                    style={{
                      backgroundColor:
                        !day || day.count === 0
                          ? "#ebedf0"
                          : day.count < 5
                            ? "#9be9a8"
                            : day.count < 10
                              ? "#40c463"
                              : "#30a14e",
                    }}
                    title={`${day?.date || "Unknown date"}: ${day?.count || 0} contributions`}
                  />
                ))}
              </div>
              <p className="text-xs text-gray-500 mt-1">Last 30 days of activity</p>
            </div>
          )}
        </div>
      )}

      {/* Recent Activity Section */}
      {githubStats.recentActivity && githubStats.recentActivity.length > 0 && (
        <div className="mb-4">
          <h4 className="font-semibold mb-2">Recent Activity</h4>
          <div className="max-h-60 overflow-y-auto">
            <ul className="divide-y">
              {githubStats.recentActivity.map((activity, index) => (
                <li key={index} className="py-2">
                  <div className="flex items-start">
                    <div className="w-8 h-8 flex-shrink-0 bg-blue-100 rounded-full flex items-center justify-center mr-2">
                      {activity.type === "PushEvent" && <span>🔄</span>}
                      {activity.type === "PullRequestEvent" && <span>🔀</span>}
                      {activity.type === "IssuesEvent" && <span>❗</span>}
                      {activity.type === "CreateEvent" && <span>➕</span>}
                      {activity.type === "DeleteEvent" && <span>➖</span>}
                      {activity.type === "WatchEvent" && <span>⭐</span>}
                      {activity.type === "ForkEvent" && <span>🍴</span>}
                      {!activity.type && <span>📝</span>}
                    </div>
                    <div className="flex-1">
                      <p className="text-sm">{activity.description || "Unknown activity"}</p>
                      <div className="flex justify-between text-xs text-gray-500 mt-1">
                        <a
                          href={activity.url || "#"}
                          target="_blank"
                          rel="noopener noreferrer"
                          className="text-blue-600 hover:underline"
                        >
                          {activity.repo || "Unknown repository"}
                        </a>
                        <span>{formatDate(activity.date)}</span>
                      </div>
                    </div>
                  </div>
                </li>
              ))}
            </ul>
          </div>
        </div>
      )}

      {githubStats.languages && githubStats.languages.length > 0 && (
        <div className="mb-4">
          <h4 className="font-semibold mb-2">Top Languages</h4>
          <div className="flex flex-wrap gap-2">
            {githubStats.languages.map((lang, index) => (
              <span key={index} className="bg-blue-100 text-blue-800 px-2 py-1 rounded text-sm">
                {lang.name || "Unknown"} ({lang.count || 0})
              </span>
            ))}
          </div>
        </div>
      )}

      <h4 className="font-semibold mb-2">Top Repositories</h4>
      {githubStats.topRepos && githubStats.topRepos.length > 0 ? (
        <ul className="divide-y">
          {githubStats.topRepos.map((repo, index) => (
            <li key={repo.name || index} className="py-2">
              <a
                href={repo.url || "#"}
                target="_blank"
                rel="noopener noreferrer"
                className="text-blue-600 hover:underline font-medium"
              >
                {repo.name || "Unknown repository"}
              </a>
              <p className="text-sm text-gray-600">{repo.description || "No description available"}</p>
              <div className="flex gap-4 mt-1 text-sm">
                <span>⭐ {repo.stars || 0}</span>
                <span>🍴 {repo.forks || 0}</span>
                {repo.language && <span>{repo.language}</span>}
              </div>
            </li>
          ))}
        </ul>
      ) : (
        <p className="text-sm text-gray-600">No repository data available</p>
      )}
    </div>
  )
}

export default GithubStats
